INSERT INTO feature_flags (key, description, global_enabled, "default") VALUES ('retention_engine_enabled', 'Master per-tenant gate for the time-based data retention engine (runRetentionSweep). OFF by default (fail-closed): while off the sweep skips the tenant entirely and records nothing. Flip on per tenant to allow shadow counting; an actual delete still additionally requires a class in enforce mode.', false, false) ON CONFLICT (key) DO NOTHING;--> statement-breakpoint
INSERT INTO feature_flags (key, description, global_enabled, "default") VALUES ('bulk_import_enabled', 'Per-tenant rollout gate for the bulk COPY-staging import pipeline (POST /imports/bulk). OFF by default (fail-closed). Effective only when the global BULK_IMPORT_ENABLED env kill-switch is also on; with both on the tenant may create bulk import jobs.', false, false) ON CONFLICT (key) DO NOTHING;
